 1	import React, { FC } from 'react';
 2	
 3	import { modelToGroupVersionKind, ProjectModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import Loading from '@kubevirt-utils/components/Loading/Loading';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { K8sResourceKind, ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 7	import {
 8	  Alert,
 9	  AlertVariant,
10	  Button,
11	  ButtonVariant,
12	  Flex,
13	  FlexItem,
14	  pluralize,
15	  Popover,
16	} from '@patternfly/react-core';
17	
18	type ProjectCheckerAlertProps = {
19	  projectsLoaded: boolean;
20	  qualifiedProjects: K8sResourceKind[];
21	};
22	
23	const ProjectCheckerAlert: FC<ProjectCheckerAlertProps> = ({
24	  projectsLoaded,
25	  qualifiedProjects = [],
26	}) => {
27	  const { t } = useKubevirtTranslation();
28	  if (!projectsLoaded) {
29	    return <Loading />;
30	  }
31	
32	  const numQualifiedProjects = qualifiedProjects?.length;
33	  const matchingProjectText = pluralize(numQualifiedProjects, 'Project');
34	
35	  return (
36	    <Alert
37	      title={
38	        <>
39	          {numQualifiedProjects ? (
40	            <>
41	              {t('{{matchingProjectText}} matching', {
42	                matchingProjectText: matchingProjectText,
43	              })}
44	            </>
45	          ) : (
46	            t('No matching Projects found for the labels')
47	          )}
48	        </>
49	      }
50	      isInline
51	      variant={numQualifiedProjects ? AlertVariant.success : AlertVariant.warning}
52	    >
53	      {numQualifiedProjects ? (
54	        <Popover
55	          bodyContent={
56	            <>
57	              {qualifiedProjects?.map((project) => (
58	                <Flex key={project.metadata.uid}>
59	                  <FlexItem spacer={{ default: 'spacerXs' }}>
60	                    <ResourceLink
61	                      groupVersionKind={modelToGroupVersionKind(ProjectModel)}
62	                      name={project.metadata.name}
63	                    />
64	                  </FlexItem>
65	                </Flex>
66	              ))}
67	            </>
68	          }
69	          headerContent={
70	            <>
71	              {t('{{qualifiedProjectsCount}} matching Projects found', {
72	                qualifiedProjectsCount: numQualifiedProjects,
73	              })}
74	            </>
75	          }
76	        >
77	          <Button isInline variant={ButtonVariant.link}>
78	            {t('View matching {{matchingProjectText}}', { matchingProjectText })}
79	          </Button>
80	        </Popover>
81	      ) : (
82	        t('Scheduling will not be possible at this state')
83	      )}
84	    </Alert>
85	  );
86	};
87	
88	export default ProjectCheckerAlert;

